   coordinate[label=above:$ \strut  f_0$] (f0) at (spath cs:north 0.5)
   coordinate[label=below:$ \strut  r_B$] (rB) at (spath cs:south 0.75)
   coordinate[label=above:$ \strut  r_A$] (rA) at (spath cs:north 0.25)
   coordinate[label=below:$ \strut  f_1$] (f1) at (spath cs:south 0.5)
 ;
  \draw [spath/save = f01] (f0) to (f1);
  \draw [spath/save = rAB] (rA) to[out=-90,in=90] (rB);
  \path [name intersections={of=f01 and rAB}]
   coordinate[dot,label=190:$r_f$] (rf) at (intersection-1)
 ;
  \begin {scope}[on background layer]
    \fill [ catd ] (nw) rectangle (se);
    \tikzset {
     spath/split at intersections={f01}{rAB},
     spath/get components of={f01} \fcpts ,
     spath/get components of={rAB} \rcpts ,
   }
    \fill [ catc ] (rA) to[spath/use={ \getComponentOf \rcpts1 ,weld}] (rf.center) to (f0) to cycle;
    \fill [ cate ] (f0) to (rf.center) to[spath/use={ \getComponentOf \rcpts2 ,weld}] (rB) to (se) to (ne) to cycle;
    \fill [ catf ] (rf.center) to[spath/use={ \getComponentOf \rcpts2 ,weld}] (rB) to (f1) to cycle;
  \end {scope}
\end {tikzpicture}

ol.li:
Given a 2-cell { l_B \circ  f_0 } \xrightarrow {{ \lambda }}{ f_1 \circ  l_A } as depicted on the left below, its right mate { f_0 \circ  r_A } \xrightarrow {{ \rho }}{ r_B \circ  f_1 } is obtained by bending with the unit of B and the counit of A as shown below on the right:






\usepackage {string-diagrams,preamble}



   \begin {tikzpicture}[scale=0.5,baseline=($(nw)!0.5!(se)$)]
     \CreateRect { 5 }{ 3 }
     \path 
      coordinate[label=above:$ \strut f_0 $] (f0) at (spath cs:north 0.5)
      coordinate[label=above:$ \strut l_B $] (lB) at (spath cs:north 0.75)
      coordinate[label=below:$ \strut l_A $] (lA) at (spath cs:south 0.25)
      coordinate[label=below:$ \strut f_1 $] (f1) at (spath cs:south 0.5)
    ;
     \draw [spath/save = f01] (f0) to (f1);
     \draw [spath/save = lBA] (lB) to[out=-90,in=90] (lA);
     \path [name intersections={of=f01 and lBA}]
      coordinate[dot, 
  label=-10:$ \lambda $
 ] (lambda) at (intersection-1)
    ;

     \begin {scope}[on background layer]
       \fill [ catc ] (nw) rectangle (se);
       \tikzset {
        spath/split at intersections={f01}{lBA},
        spath/get components of={lBA} \lcpts ,
      }
       \fill [ cate ] (lB) to[spath/use={ \getComponentOf \lcpts1 ,weld}] (lambda.center) to (f0) to cycle;
       \fill [ catd ] (lambda.center) to[spath/use={ \getComponentOf \lcpts2 ,weld}] (lA) to (f1) to cycle;
       \fill [ catf ] (lB) to[spath/use={ \getComponentOf \lcpts1 ,weld}] (lambda.center) to (f1) to (se) to (ne) to cycle;
     \end {scope}
   \end {tikzpicture}


  $ \mapsto $


   \begin {tikzpicture}[scale=0.5,baseline=($(nw)!0.5!(se)$)]
     \CreateRect { 5 }{ 3 }
     \path 
      coordinate[label=above:$ \strut f_0 $] (f0) at (spath cs:north 0.5)
      coordinate[label=below:$ \strut r_B $] (rB) at (spath cs:south 0.90)
      coordinate[label=above:$ \strut r_A $] (rA) at (spath cs:north 0.1)
      coordinate[label=below:$ \strut f_1 $] (f1) at (spath cs:south 0.5)
    ;
     \draw [spath/save = f01] (f0) to (f1);
     \path [spath/save = diagonal] (sw) to (ne);
     \path 
      coordinate[dot,label=above:$ \epsilon _A $] (counit) at (spath cs:diagonal 0.25)
      coordinate[dot,label=below:$ \eta _B $] (unit) at (spath cs:diagonal 0.75)
    ;
     \draw [spath/save=swoosh] (rA) to[out=-90,in=180] (counit.center) to[out=0,in=180] (unit.center) to[out=0,in=90] (rB);
     \path [name intersections={of=swoosh and f01}]
      coordinate[dot, 
  label=-10:$ \lambda $
 ] (lambda) at (intersection-1)
    ;
     \begin {scope}[on background layer]
       \tikzset {
        spath/split at intersections={f01}{swoosh},
        spath/get components of={swoosh} \cpts ,
      }
       \fill [ catd ] (nw) to (rA) to[spath/use={ \getComponentOf \cpts1 ,weld}] (lambda.center) to (f1) to (sw) to cycle;
       \fill [ catc ] (rA) to[spath/use={ \getComponentOf \cpts1 ,weld}] (lambda.center) to (f0) to cycle;
       \fill [ cate ] (f0) to (lambda.center) to[spath/use={ \getComponentOf \cpts2 ,weld}] (rB) to (se) to (ne) to cycle;
       \fill [ catf ] (f1) to (lambda.center) to[spath/use={ \getComponentOf \cpts2 ,weld}] (rB) to cycle;
     \end {scope}
   \end {tikzpicture}

Given a 2-cell { f_0 \circ  r_A } \xrightarrow {{ \rho }}{ r_B \circ  f_1 } as depicted on the right below, its left mate { l_B \circ  f_0 } \xrightarrow {{ \lambda }}{ f_1 \circ  l_A } is obtained by bending with the unit of A and the counit of B as shown below on the left:






\usepackage {string-diagrams,preamble}



   \begin {tikzpicture}[scale=0.5,baseline=($(nw)!0.5!(se)$)]
     \CreateRect { 5 }{ 3 }
     \path 
      coordinate[label=above:$ \strut f_0 $] (f0) at (spath cs:north 0.5)
      coordinate[label=above:$ \strut l_B $] (lB) at (spath cs:north 0.90)
      coordinate[label=below:$ \strut l_A $] (lA) at (spath cs:south 0.1)
      coordinate[label=below:$ \strut f_1 $] (f1) at (spath cs:south 0.5)
    ;
     \draw [spath/save = f01] (f0) to (f1);
     \path [spath/save = diagonal] (se) to (nw);
     \path 
      coordinate[dot,label=below:$ \eta _A $] (unit) at (spath cs:diagonal 0.75)
      coordinate[dot,label=above:$ \epsilon _B $] (counit) at (spath cs:diagonal 0.25)
    ;
     \draw [spath/save=swoosh] (lA) to[out=90,in=180] (unit.center) to[out=0,in=180] (counit.center) to[out=0,in=-90] (lB);
     \path [name intersections={of=swoosh and f01}]
      coordinate[dot, 
  label=190:$ \rho $
 ] (rho) at (intersection-1)
    ;
     \begin {scope}[on background layer]
       \tikzset {
        spath/split at intersections={f01}{swoosh},
        spath/get components of={swoosh} \cpts ,
      }
       \fill [ catc ] (nw) to (sw) to (lA) to[spath/use={ \getComponentOf \cpts1 ,weld}] (rho.center) to (f0) to cycle;
       \fill [ catd ] (lA) to[spath/use={ \getComponentOf \cpts1 ,weld}] (rho.center) to (f1) to (sw) to cycle;
       \fill [ cate ] (f0) to (rho.center) to[spath/use={ \getComponentOf \cpts2 ,weld}] (lB) to cycle;
       \fill [ catf ] (f1) to (rho.center) to[spath/use={ \getComponentOf \cpts2 ,weld}] (lB) to (ne) to (se) to cycle;
     \end {scope}
   \end {tikzpicture}


